import org.apache.commons.lang3.StringEscapeUtils;
import java.util.Scanner;

public class SecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize user input to prevent XSS
        String sanitizedName = StringEscapeUtils.escapeHtml4(name);

        System.out.println("Hello, " + sanitizedName + "!"); // Safe code

        // Malicious script will be treated as plain text and not executed
        System.out.println("<script>alert('XSS Attack!')</script>");

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
